/*
 * This file was generated by the Gradle 'init' task.
 */

plugins {
    id("buildlogic.server-conventions")
    id("com.gradleup.shadow")
}

dependencies {
    implementation(libs.org.agrona.agrona)
    implementation(project(":zeebe-util"))
    implementation(project(":zeebe-msgpack-value"))
    implementation(libs.com.github.ben.manes.caffeine.caffeine)
    implementation(libs.org.openjdk.jmh.jmh.core)
    // jmh-generator-annprocess is `provided` in Maven (declared dep) AND configured as
    // annotation processor; mirror both so generated BenchmarkList / BenchmarkProfile classes exist.
    compileOnly(libs.org.openjdk.jmh.jmh.generator.annprocess)
    annotationProcessor(libs.org.openjdk.jmh.jmh.generator.annprocess)
}

// Mirrors maven-shade-plugin: produces a `benchmarks.jar` uberjar with org.openjdk.jmh.Main
// as Main-Class and merged service files; signed jar metadata is stripped.
tasks.named<com.github.jengelman.gradle.plugins.shadow.tasks.ShadowJar>("shadowJar") {
    archiveBaseName.set("benchmarks")
    archiveClassifier.set("")
    archiveVersion.set("")
    manifest {
        attributes("Main-Class" to "org.openjdk.jmh.Main")
    }
    mergeServiceFiles()
    exclude("META-INF/*.SF", "META-INF/*.DSA", "META-INF/*.RSA")
}

description = "Camunda Microbenchmarks"
